public class PabloException: UniffiException {
    PabloException() : base() {}
    PabloException(String @Message) : base(@Message) {}

    // Each variant is a nested class
    
    
    public class AudioPreprocessing : PabloException {
        // Members
        public string @message;

        // Constructor
        public AudioPreprocessing(
                string @message) : base(
                "@message" + "=" + @message) {

            this.@message = @message;
        }
    }
    
    
    public class WhisperInit : PabloException {
        // Members
        public string @message;

        // Constructor
        public WhisperInit(
                string @message) : base(
                "@message" + "=" + @message) {

            this.@message = @message;
        }
    }
    
    
    public class WhisperTranscribe : PabloException {
        // Members
        public string @message;

        // Constructor
        public WhisperTranscribe(
                string @message) : base(
                "@message" + "=" + @message) {

            this.@message = @message;
        }
    }
    
    
    public class ApiClient : PabloException {
        // Members
        public ushort @statusCode;
        public string @message;

        // Constructor
        public ApiClient(
                ushort @statusCode, 
                string @message) : base(
                "@statusCode" + "=" + @statusCode+ ", " +
                "@message" + "=" + @message) {

            this.@statusCode = @statusCode;

            this.@message = @message;
        }
    }
    
    
    public class JsonParse : PabloException {
        // Members
        public string @message;

        // Constructor
        public JsonParse(
                string @message) : base(
                "@message" + "=" + @message) {

            this.@message = @message;
        }
    }
    
    
    public class Unauthenticated : PabloException {
        public Unauthenticated() : base() {}
    }
    
    
    
    public class Forbidden : PabloException {
        public Forbidden() : base() {}
    }
    
    
    
    public class NotFound : PabloException {
        // Members
        public string @resource;

        // Constructor
        public NotFound(
                string @resource) : base(
                "@resource" + "=" + @resource) {

            this.@resource = @resource;
        }
    }
    
    
    public class ConflictState : PabloException {
        // Members
        public string @message;

        // Constructor
        public ConflictState(
                string @message) : base(
                "@message" + "=" + @message) {

            this.@message = @message;
        }
    }
    

    
}

class FfiConverterTypePabloError : FfiConverterRustBuffer<PabloException>, CallStatusErrorHandler<PabloException> {
    public static FfiConverterTypePabloError INSTANCE = new FfiConverterTypePabloError();

    public override PabloException Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new PabloException.AudioPreprocessing(
                    FfiConverterString.INSTANCE.Read(stream));
            case 2:
                return new PabloException.WhisperInit(
                    FfiConverterString.INSTANCE.Read(stream));
            case 3:
                return new PabloException.WhisperTranscribe(
                    FfiConverterString.INSTANCE.Read(stream));
            case 4:
                return new PabloException.ApiClient(
                    FfiConverterUInt16.INSTANCE.Read(stream),
                    FfiConverterString.INSTANCE.Read(stream));
            case 5:
                return new PabloException.JsonParse(
                    FfiConverterString.INSTANCE.Read(stream));
            case 6:
                return new PabloException.Unauthenticated();
            case 7:
                return new PabloException.Forbidden();
            case 8:
                return new PabloException.NotFound(
                    FfiConverterString.INSTANCE.Read(stream));
            case 9:
                return new PabloException.ConflictState(
                    FfiConverterString.INSTANCE.Read(stream));
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypePabloError.Read()", value));
        }
    }

    public override int AllocationSize(PabloException value) {
        switch (value) {

            case PabloException.AudioPreprocessing variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@message);

            case PabloException.WhisperInit variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@message);

            case PabloException.WhisperTranscribe variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@message);

            case PabloException.ApiClient variant_value:
                return 4
                    + FfiConverterUInt16.INSTANCE.AllocationSize(variant_value.@statusCode)
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@message);

            case PabloException.JsonParse variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@message);

            case PabloException.Unauthenticated variant_value:
                return 4;

            case PabloException.Forbidden variant_value:
                return 4;

            case PabloException.NotFound variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@resource);

            case PabloException.ConflictState variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@message);
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypePabloError.AllocationSize()", value));
        }
    }

    public override void Write(PabloException value, BigEndianStream stream) {
        switch (value) {
            case PabloException.AudioPreprocessing variant_value:
                stream.WriteInt(1);
                FfiConverterString.INSTANCE.Write(variant_value.@message, stream);
                break;
            case PabloException.WhisperInit variant_value:
                stream.WriteInt(2);
                FfiConverterString.INSTANCE.Write(variant_value.@message, stream);
                break;
            case PabloException.WhisperTranscribe variant_value:
                stream.WriteInt(3);
                FfiConverterString.INSTANCE.Write(variant_value.@message, stream);
                break;
            case PabloException.ApiClient variant_value:
                stream.WriteInt(4);
                FfiConverterUInt16.INSTANCE.Write(variant_value.@statusCode, stream);
                FfiConverterString.INSTANCE.Write(variant_value.@message, stream);
                break;
            case PabloException.JsonParse variant_value:
                stream.WriteInt(5);
                FfiConverterString.INSTANCE.Write(variant_value.@message, stream);
                break;
            case PabloException.Unauthenticated variant_value:
                stream.WriteInt(6);
                break;
            case PabloException.Forbidden variant_value:
                stream.WriteInt(7);
                break;
            case PabloException.NotFound variant_value:
                stream.WriteInt(8);
                FfiConverterString.INSTANCE.Write(variant_value.@resource, stream);
                break;
            case PabloException.ConflictState variant_value:
                stream.WriteInt(9);
                FfiConverterString.INSTANCE.Write(variant_value.@message, stream);
                break;
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypePabloError.Write()", value));
        }
    }
}





